import matplotlib.pyplot as pltimport matplotlib.patches as mpatchesimport numpy as np#graph of round-by-round global model accuracydef plot_accuracy_curve(history, num_rounds, save_path="/Users/apple/Desktop/Msc Project/Artefact/project-main/results/accuracy_curve.png"):      rounds     = [m[0] for m in history.metrics_distributed['accuracy']]    accuracies = [m[1] for m in history.metrics_distributed['accuracy']]    plt.figure(figsize=(10, 6))    plt.plot(rounds, accuracies,              marker='o',              linewidth=2.5,              markersize=8,             color='steelblue',             label='Global Model Accuracy')    #Annotate each point with its value    for r, a in zip(rounds, accuracies):        plt.annotate(f'{a:.4f}',                      xy=(r, a),                     xytext=(0, 10),                     textcoords='offset points',                     ha='center',                     fontsize=9)    plt.title('Federated Learning — Global Model Accuracy per Round\n(IID Partition, FedAvg, 10 Clients)',              fontsize=13, fontweight='bold')    plt.xlabel('Communication Round', fontsize=12)    plt.ylabel('Accuracy', fontsize=12)    plt.xticks(rounds)    plt.ylim(0.70, 1.0)    plt.grid(True, linestyle='--', alpha=0.6)    plt.legend(fontsize=11)    plt.tight_layout()    plt.savefig(save_path, dpi=300)    plt.close()    print(f"Saved: {save_path}")#Bar chart showing per-round accuracy gain#How much the model improved per rounddef plot_accuracy_improvement(history, save_path="/Users/apple/Desktop/Msc Project/Artefact/project-main/results/accuracy_improvement.png"):        accuracies = [m[1] for m in history.metrics_distributed['accuracy']]    rounds     = list(range(1, len(accuracies) + 1))    gains      = [accuracies[0]] + [accuracies[i] - accuracies[i-1]                                      for i in range(1, len(accuracies))]    colours = ['steelblue' if g > 0 else 'tomato' for g in gains]    plt.figure(figsize=(10, 6))    bars = plt.bar(rounds, gains, color=colours, edgecolor='white', linewidth=0.8)    #Label each bar    for bar, gain in zip(bars, gains):        plt.text(bar.get_x() + bar.get_width() / 2,                 bar.get_height() + 0.002,                 f'+{gain:.4f}' if gain > 0 else f'{gain:.4f}',                 ha='center', va='bottom', fontsize=9)    plt.title('Per-Round Accuracy Improvement\n(IID Partition, FedAvg, 10 Clients)',              fontsize=13, fontweight='bold')    plt.xlabel('Communication Round', fontsize=12)    plt.ylabel('Accuracy Gain', fontsize=12)    plt.xticks(rounds)    plt.grid(True, axis='y', linestyle='--', alpha=0.6)    plt.tight_layout()    plt.savefig(save_path, dpi=300)    plt.close()    print(f"Saved: {save_path}")#Bar chart comparing single client baseline vs federated global modeldef plot_single_vs_federated(single_client_acc, federated_final_acc,                              save_path="/Users/apple/Desktop/Msc Project/Artefact/project-main/results/single_vs_federated.png"):      labels = ['Single Client\n(Client 0, No Federation)',               'Federated Global Model\n(10 Clients, FedAvg)']    values = [single_client_acc, federated_final_acc]    colours = ['tomato', 'steelblue']    plt.figure(figsize=(8, 6))    bars = plt.bar(labels, values, color=colours,                    width=0.4, edgecolor='white', linewidth=0.8)    for bar, val in zip(bars, values):        plt.text(bar.get_x() + bar.get_width() / 2,                 bar.get_height() + 0.005,                 f'{val:.4f}',                 ha='center', va='bottom',                  fontsize=12, fontweight='bold')    plt.title('Single Client vs Federated Learning\nAccuracy Comparison',              fontsize=13, fontweight='bold')    plt.ylabel('Accuracy', fontsize=12)    plt.ylim(0.0, 1.0)    plt.grid(True, axis='y', linestyle='--', alpha=0.6)    plt.tight_layout()    plt.savefig(save_path, dpi=300)    plt.close()    print(f"Saved: {save_path}")#how close the model is to its final accuracy each round (convergence speed)def plot_convergence_rate(history, save_path="/Users/apple/Desktop/Msc Project/Artefact/project-main/results/convergence_rate.png"):      accuracies  = [m[1] for m in history.metrics_distributed['accuracy']]    rounds      = list(range(1, len(accuracies) + 1))    final_acc   = accuracies[-1]    gap_to_final = [final_acc - a for a in accuracies]    plt.figure(figsize=(10, 6))    plt.fill_between(rounds, gap_to_final, alpha=0.3, color='steelblue')    plt.plot(rounds, gap_to_final,              marker='s', linewidth=2.5,              markersize=8, color='steelblue',             label='Gap to Final Accuracy')    plt.title('Convergence Rate — Gap to Final Accuracy per Round\n(IID Partition, FedAvg, 10 Clients)',              fontsize=13, fontweight='bold')    plt.xlabel('Communication Round', fontsize=12)    plt.ylabel('Remaining Accuracy Gap', fontsize=12)    plt.xticks(rounds)    plt.grid(True, linestyle='--', alpha=0.6)    plt.legend(fontsize=11)    plt.tight_layout()    plt.savefig(save_path, dpi=300)    plt.close()    print(f"Saved: {save_path}")#One func for all 4 grpahsdef generate_all_plots(history, single_client_acc=0.8601):       import os    os.makedirs("results", exist_ok=True)    num_rounds = len(history.metrics_distributed['accuracy'])    plot_accuracy_curve(history, num_rounds)    plot_accuracy_improvement(history)    plot_single_vs_federated(single_client_acc,                               history.metrics_distributed['accuracy'][-1][1])    plot_convergence_rate(history)    print("\nAll graphs saved to /results folder.")